module RefModule(
    input clk,
    input rst,
    input en,
    input dir,
    output reg [7:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk)
begin
  if (rst)
    count <= 0;
  else if (en)
  begin
    if (dir)
      count <= count + 1;
    else
      count <= count - 1;
  end
end

endmodule
